// ============================================================
// PREPARAR INSERT MYSQL
// ============================================================

const dados = msg.payload;

// Preserva o tópico MQTT antes de sobrescrever msg.topic
const topicoMqtt = String(msg.topic ?? "");

if (
    dados === null ||
    typeof dados !== "object" ||
    Array.isArray(dados)
) {
    node.warn("Payload MQTT inválido.");
    return null;
}

// ============================================================
// CAMPOS OBRIGATÓRIOS
// ============================================================

const deviceId = String(
    dados.device_id ?? ""
).trim();

const temperatura = Number(
    dados.temperature
);

if (deviceId === "") {
    node.warn("Mensagem sem device_id.");
    return null;
}

if (!Number.isFinite(temperatura)) {
    node.warn("Temperatura inválida.");
    return null;
}

// ============================================================
// FUNÇÕES AUXILIARES
// ============================================================

function booleano(valor) {
    return (
        valor === true ||
        Number(valor) === 1
    ) ? 1 : 0;
}

function numeroOpcional(valor) {
    const numero = Number(valor);

    return Number.isFinite(numero)
        ? numero
        : null;
}

// ============================================================
// TRATAMENTO DOS CAMPOS
// ============================================================

const setpoint = numeroOpcional(
    dados.setpoint ??
    dados.threshold
);

const acimaSetpoint =
    dados.temperature_above_setpoint !== undefined
        ? booleano(dados.temperature_above_setpoint)
        : (
            setpoint !== null &&
                temperatura > setpoint
                ? 1
                : 0
        );

const botao = booleano(
    dados.button
);

const alarme = booleano(
    dados.alarm
);

const sprinkler = booleano(
    dados.sprinkler
);

const ledVerde = booleano(
    dados.led_green
);

const ledAlarme = booleano(
    dados.led_alarm
);

const estado = String(
    dados.state ??
    (
        alarme === 1
            ? "risco_incendio"
            : "normal"
    )
).trim();

const wifiRssi = numeroOpcional(
    dados.wifi_rssi
);

const uptimeRecebido = numeroOpcional(
    dados.uptime_ms
);

const uptimeMs =
    uptimeRecebido === null
        ? null
        : Math.trunc(uptimeRecebido);

const temperaturaArredondada =
    Math.round(temperatura * 100) / 100;

const setpointArredondado =
    setpoint === null
        ? null
        : Math.round(setpoint * 100) / 100;

// ============================================================
// INSERT PARAMETRIZADO
// ============================================================

msg.topic = `
    INSERT INTO leituras_esp32 (
        device_id,
        mqtt_topic,
        temperatura,
        setpoint,
        acima_setpoint,
        botao,
        alarme,
        sprinkler,
        led_verde,
        led_alarme,
        estado,
        wifi_rssi,
        uptime_ms
    )
    VALUES (
        ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?
    );
`;

msg.payload = [
    deviceId,
    topicoMqtt,
    temperaturaArredondada,
    setpointArredondado,
    acimaSetpoint,
    botao,
    alarme,
    sprinkler,
    ledVerde,
    ledAlarme,
    estado,
    wifiRssi,
    uptimeMs
];

return msg;

