// ============================================================
// PREPARAR CONSULTAS DOS TRÊS HISTÓRICOS
// ============================================================

const consulta = `
    SELECT
        UNIX_TIMESTAMP(
            MIN(recebido_em)
        ) * 1000 AS timestamp_ms,

        MAX(alarme) AS alarme,
        MAX(sprinkler) AS sprinkler

    FROM leituras_esp32

    WHERE device_id = ?

    AND recebido_em >=
        NOW() - INTERVAL 6 HOUR

    GROUP BY
        FLOOR(
            UNIX_TIMESTAMP(recebido_em) / 10
        )

    ORDER BY
        timestamp_ms ASC;
`;

function criarMensagem(deviceId) {
    return {
        device_id: deviceId,
        topic: consulta,
        payload: [deviceId]
    };
}

return [
    criarMensagem("esp32-01"),
    criarMensagem("esp32-02"),
    criarMensagem("esp32-03")
];

// ============================================================
// FORMATAR HISTÓRICO OPERACIONAL
//
// Saída 1: ESP32-01
// Saída 2: ESP32-02
// Saída 3: ESP32-03
// ============================================================

const JANELA_MS =
    6 * 60 * 60 * 1000;

const INTERVALO_AMOSTRA_MS =
    10 * 1000;

const LIMITE_OFFLINE_MS =
    30 * 1000;

const fimJanela = Date.now();
const inicioJanela =
    fimJanela - JANELA_MS;

const linhas = Array.isArray(msg.payload)
    ? msg.payload
        .map(linha => ({
            timestamp:
                Number(linha.timestamp_ms),

            alarme:
                Number(linha.alarme) === 1
                    ? 1
                    : 0,

            sprinkler:
                Number(linha.sprinkler) === 1
                    ? 1
                    : 0
        }))
        .filter(linha =>
            Number.isFinite(
                linha.timestamp
            )
        )
        .sort(
            (a, b) =>
                a.timestamp -
                b.timestamp
        )
    : [];

// ============================================================
// ADICIONAR INTERVALO
// ============================================================

function adicionarIntervalo(
    intervalos,
    inicio,
    fim,
    estado
) {
    const inicioLimitado =
        Math.max(
            inicio,
            inicioJanela
        );

    const fimLimitado =
        Math.min(
            fim,
            fimJanela
        );

    if (
        fimLimitado >
        inicioLimitado
    ) {
        intervalos.push({
            start: inicioLimitado,
            end: fimLimitado,
            state: estado
        });
    }
}

// ============================================================
// CONSTRUIR INTERVALOS
// ============================================================

function construirIntervalos(
    campo,
    estadoAtivo,
    estadoInativo
) {
    const intervalos = [];

    if (linhas.length === 0) {
        adicionarIntervalo(
            intervalos,
            inicioJanela,
            fimJanela,
            "offline"
        );

        return intervalos;
    }

    const primeiraLinha =
        linhas[0];

    const primeiroTimestamp =
        primeiraLinha.timestamp;

    if (
        primeiroTimestamp -
        inicioJanela >
        LIMITE_OFFLINE_MS
    ) {
        adicionarIntervalo(
            intervalos,
            inicioJanela,
            primeiroTimestamp,
            "offline"
        );
    }

    let estadoAtual =
        primeiraLinha[campo] === 1
            ? estadoAtivo
            : estadoInativo;

    let inicioEstado =
        primeiroTimestamp -
        inicioJanela <=
        LIMITE_OFFLINE_MS
            ? inicioJanela
            : primeiroTimestamp;

    let timestampAnterior =
        primeiroTimestamp;

    for (
        let i = 1;
        i < linhas.length;
        i++
    ) {
        const linha =
            linhas[i];

        const timestamp =
            linha.timestamp;

        const novoEstado =
            linha[campo] === 1
                ? estadoAtivo
                : estadoInativo;

        const intervaloSemDados =
            timestamp -
            timestampAnterior;

        // Período sem comunicação
        if (
            intervaloSemDados >
            LIMITE_OFFLINE_MS
        ) {
            adicionarIntervalo(
                intervalos,
                inicioEstado,
                timestampAnterior +
                    INTERVALO_AMOSTRA_MS,
                estadoAtual
            );

            adicionarIntervalo(
                intervalos,
                timestampAnterior +
                    INTERVALO_AMOSTRA_MS,
                timestamp,
                "offline"
            );

            estadoAtual =
                novoEstado;

            inicioEstado =
                timestamp;
        }
        // Mudança de estado
        else if (
            novoEstado !==
            estadoAtual
        ) {
            adicionarIntervalo(
                intervalos,
                inicioEstado,
                timestamp,
                estadoAtual
            );

            estadoAtual =
                novoEstado;

            inicioEstado =
                timestamp;
        }

        timestampAnterior =
            timestamp;
    }

    const tempoSemRegistro =
        fimJanela -
        timestampAnterior;

    if (
        tempoSemRegistro >
        LIMITE_OFFLINE_MS
    ) {
        adicionarIntervalo(
            intervalos,
            inicioEstado,
            timestampAnterior +
                INTERVALO_AMOSTRA_MS,
            estadoAtual
        );

        adicionarIntervalo(
            intervalos,
            timestampAnterior +
                INTERVALO_AMOSTRA_MS,
            fimJanela,
            "offline"
        );
    } else {
        adicionarIntervalo(
            intervalos,
            inicioEstado,
            fimJanela,
            estadoAtual
        );
    }

    return intervalos;
}

// ============================================================
// PAYLOAD PARA O DASHBOARD
// ============================================================

const resposta = {
    device_id:
        msg.device_id,

    start:
        inicioJanela,

    end:
        fimJanela,

    updated_at:
        Date.now(),

    alarm_intervals:
        construirIntervalos(
            "alarme",
            "alerta",
            "normal"
        ),

    sprinkler_intervals:
        construirIntervalos(
            "sprinkler",
            "ativo",
            "inativo"
        )
};

const mensagem = {
    payload: resposta
};

switch (msg.device_id) {
    case "esp32-01":
        return [
            mensagem,
            null,
            null
        ];

    case "esp32-02":
        return [
            null,
            mensagem,
            null
        ];

    case "esp32-03":
        return [
            null,
            null,
            mensagem
        ];

    default:
        node.warn(
            `Dispositivo desconhecido: ${msg.device_id}`
        );

        return [
            null,
            null,
            null
        ];
}

// ============================================================
// CONSULTAS DA PÁGINA DE ANÁLISES
//
// Saída 1: gráfico
// Saída 2: indicadores
// Saída 3: tabela
// ============================================================

// ------------------------------------------------------------
// Funções de normalização
// ------------------------------------------------------------

function normalizarDispositivo(valor) {
    const texto = String(valor ?? "")
        .trim();

    const mapa = {
        "ESP32 #1": "esp32-01",
        "ESP32 #2": "esp32-02",
        "ESP32 #3": "esp32-03",
        "Todos": "all",

        "esp32-01": "esp32-01",
        "esp32-02": "esp32-02",
        "esp32-03": "esp32-03",
        "all": "all"
    };

    return mapa[texto] ?? texto;
}

function normalizarData(valor) {
    const texto = String(valor ?? "")
        .trim();

    // Formato esperado pelo input HTML:
    // 2026-06-21
    if (/^\d{4}-\d{2}-\d{2}$/.test(texto)) {
        return texto;
    }

    // Aceita também:
    // 21/06/2026
    const formatoBR = texto.match(
        /^(\d{2})\/(\d{2})\/(\d{4})$/
    );

    if (formatoBR) {
        return (
            `${formatoBR[3]}-` +
            `${formatoBR[2]}-` +
            `${formatoBR[1]}`
        );
    }

    return "";
}

function normalizarHora(valor) {
    const texto = String(valor ?? "")
        .trim();

    const resultado = texto.match(
        /^(\d{1,2}):(\d{2})/
    );

    if (!resultado) {
        return "";
    }

    const hora = String(resultado[1])
        .padStart(2, "0");

    const minuto = resultado[2];

    return `${hora}:${minuto}`;
}

// ------------------------------------------------------------
// Recuperação dos filtros
// ------------------------------------------------------------

const deviceId = normalizarDispositivo(
    flow.get("analysis_device") ??
    "esp32-01"
);

const dataInicio = normalizarData(
    flow.get("analysis_start_date")
);

const horaInicio = normalizarHora(
    flow.get("analysis_start_time")
);

const dataFim = normalizarData(
    flow.get("analysis_end_date")
);

const horaFim = normalizarHora(
    flow.get("analysis_end_time")
);

const dispositivosPermitidos = [
    "all",
    "esp32-01",
    "esp32-02",
    "esp32-03"
];

if (!dispositivosPermitidos.includes(deviceId)) {
    node.error(
        `Dispositivo inválido: ${deviceId}`,
        msg
    );

    return [null, null, null];
}

// ------------------------------------------------------------
// Período
// ------------------------------------------------------------

let filtroPeriodo;
let parametrosPeriodo;
let descricaoPeriodo;

const periodoCompleto =
    dataInicio !== "" &&
    horaInicio !== "" &&
    dataFim !== "" &&
    horaFim !== "";

if (periodoCompleto) {
    const inicio =
        `${dataInicio} ${horaInicio}:00`;

    const fim =
        `${dataFim} ${horaFim}:59`;

    if (fim < inicio) {
        node.error(
            "A data final deve ser posterior à data inicial.",
            msg
        );

        return [null, null, null];
    }

    filtroPeriodo = `
        recebido_em BETWEEN ? AND ?
    `;

    parametrosPeriodo = [
        inicio,
        fim
    ];

    descricaoPeriodo =
        `${inicio} até ${fim}`;
} else {
    /*
     * Fallback:
     * caso os valores iniciais dos widgets ainda não tenham
     * sido enviados, consulta as últimas 48 horas.
     */
    filtroPeriodo = `
        recebido_em BETWEEN
        NOW() - INTERVAL 2 DAY
        AND NOW()
    `;

    parametrosPeriodo = [];

    descricaoPeriodo =
        "últimas 48 horas";

    node.warn(
        "Os filtros de data não estavam disponíveis. " +
        "Utilizando as últimas 48 horas."
    );
}

// ------------------------------------------------------------
// Filtro do dispositivo
// ------------------------------------------------------------

let filtroDispositivo = "";
let parametrosConsulta = [
    ...parametrosPeriodo
];

if (deviceId !== "all") {
    filtroDispositivo = `
        AND device_id = ?
    `;

    parametrosConsulta.push(
        deviceId
    );
}

// ------------------------------------------------------------
// Consulta 1: gráfico
// ------------------------------------------------------------

const mensagemGrafico = {
    query_type: "chart",

    filtros: {
        device_id: deviceId,
        periodo: descricaoPeriodo
    },

    topic: `
        SELECT
            device_id,

            FLOOR(
                UNIX_TIMESTAMP(recebido_em) / 60
            ) * 60000 AS timestamp_ms,

            ROUND(
                AVG(temperatura),
                2
            ) AS temperatura,

            ROUND(
                AVG(setpoint),
                2
            ) AS setpoint

        FROM leituras_esp32

        WHERE ${filtroPeriodo}

        ${filtroDispositivo}

        GROUP BY
            device_id,
            FLOOR(
                UNIX_TIMESTAMP(recebido_em) / 60
            )

        ORDER BY
            timestamp_ms ASC,
            device_id ASC;
    `,

    payload: [
        ...parametrosConsulta
    ]
};

// ------------------------------------------------------------
// Consulta 2: indicadores
// ------------------------------------------------------------

const mensagemKPI = {
    query_type: "kpi",

    filtros: {
        device_id: deviceId,
        periodo: descricaoPeriodo
    },

    topic: `
        SELECT
            ROUND(
                MIN(temperatura),
                1
            ) AS temperatura_minima,

            ROUND(
                AVG(temperatura),
                1
            ) AS temperatura_media,

            ROUND(
                MAX(temperatura),
                1
            ) AS temperatura_maxima,

            ROUND(
                AVG(alarme) * 100,
                1
            ) AS percentual_alerta,

            COUNT(*) AS total_registros

        FROM leituras_esp32

        WHERE ${filtroPeriodo}

        ${filtroDispositivo};
    `,

    payload: [
        ...parametrosConsulta
    ]
};

// ------------------------------------------------------------
// Consulta 3: tabela
// ------------------------------------------------------------

const mensagemTabela = {
    query_type: "table",

    filtros: {
        device_id: deviceId,
        periodo: descricaoPeriodo
    },

    topic: `
        SELECT
            device_id AS dispositivo,

            DATE_FORMAT(
                recebido_em,
                '%d/%m/%Y %H:%i:%s'
            ) AS horario,

            ROUND(
                temperatura,
                1
            ) AS temperatura,

            ROUND(
                setpoint,
                1
            ) AS setpoint,

            CASE
                WHEN alarme = 1
                    THEN 'ALERTA'
                ELSE 'NORMAL'
            END AS estado,

            CASE
                WHEN sprinkler = 1
                    THEN 'ATIVO'
                ELSE 'INATIVO'
            END AS sprinkler

        FROM leituras_esp32

        WHERE ${filtroPeriodo}

        ${filtroDispositivo}

        ORDER BY
            recebido_em DESC

        LIMIT 200;
    `,

    payload: [
        ...parametrosConsulta
    ]
};

// ------------------------------------------------------------
// Estado visual da função
// ------------------------------------------------------------

node.status({
    fill: "green",
    shape: "dot",
    text:
        `${deviceId} | ${descricaoPeriodo}`
});

return [
    mensagemGrafico,
    mensagemKPI,
    mensagemTabela
];

// ============================================================
// GRÁFICO HISTÓRICO — TEMPERATURA E SETPOINT
//
// Cria uma série independente para cada variável:
//
// ESP32 #1 - Temperatura
// ESP32 #1 - Setpoint
// ESP32 #2 - Temperatura
// ESP32 #2 - Setpoint
// ESP32 #3 - Temperatura
// ESP32 #3 - Setpoint
// ============================================================

const linhas = Array.isArray(msg.payload)
    ? msg.payload
    : [];

if (linhas.length === 0) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: "consulta sem registros"
    });

    return [[{
        payload: [],
        action: "replace"
    }]];
}

// ============================================================
// CONFIGURAÇÃO DOS DISPOSITIVOS
// ============================================================

const dispositivos = {
    "esp32-01": {
        nome: "ESP32 #1",
        corTemperatura: "#1565C0",
        corSetpoint: "#00ACC1"
    },

    "esp32-02": {
        nome: "ESP32 #2",
        corTemperatura: "#2E7D32",
        corSetpoint: "#8BC34A"
    },

    "esp32-03": {
        nome: "ESP32 #3",
        corTemperatura: "#EF6C00",
        corSetpoint: "#8E24AA"
    }
};

const ordemDispositivos = [
    "esp32-01",
    "esp32-02",
    "esp32-03"
];

// ============================================================
// OBJETO PARA SEPARAR OS PONTOS
// ============================================================

const dadosPorDispositivo = {};

for (const deviceId of ordemDispositivos) {
    dadosPorDispositivo[deviceId] = {
        temperatura: [],
        setpoint: []
    };
}

// ============================================================
// DISTRIBUIÇÃO DOS DADOS
// ============================================================

for (const linha of linhas) {
    const deviceId = String(
        linha.device_id ?? ""
    ).trim();

    if (!dadosPorDispositivo[deviceId]) {
        continue;
    }

    const timestamp = Number(
        linha.timestamp_ms
    );

    const temperatura = Number(
        linha.temperatura
    );

    const setpoint = Number(
        linha.setpoint
    );

    if (!Number.isFinite(timestamp)) {
        continue;
    }

    if (Number.isFinite(temperatura)) {
        dadosPorDispositivo[
            deviceId
        ].temperatura.push({
            x: timestamp,
            y: temperatura
        });
    }

    if (Number.isFinite(setpoint)) {
        dadosPorDispositivo[
            deviceId
        ].setpoint.push({
            x: timestamp,
            y: setpoint
        });
    }
}

// ============================================================
// CRIAÇÃO DAS MENSAGENS DAS SÉRIES
// ============================================================

const mensagensDados = [];
const configuracaoSeries = [];

for (const deviceId of ordemDispositivos) {
    const configuracao =
        dispositivos[deviceId];

    const dados =
        dadosPorDispositivo[deviceId];

    // Ordena cronologicamente
    dados.temperatura.sort(
        (a, b) => a.x - b.x
    );

    dados.setpoint.sort(
        (a, b) => a.x - b.x
    );

    // --------------------------------------------------------
    // Série de temperatura
    // --------------------------------------------------------

    if (dados.temperatura.length > 0) {
        const nomeSerie =
            `${configuracao.nome} - Temperatura`;

        mensagensDados.push({
            topic: nomeSerie,
            payload: dados.temperatura
        });

        configuracaoSeries.push({
            name: nomeSerie,
            type: "line",

            lineStyle: {
                color:
                    configuracao.corTemperatura,
                width: 3,
                type: "solid"
            },

            itemStyle: {
                color:
                    configuracao.corTemperatura
            }
        });
    }

    // --------------------------------------------------------
    // Série de setpoint
    // --------------------------------------------------------

    if (dados.setpoint.length > 0) {
        const nomeSerie =
            `${configuracao.nome} - Setpoint`;

        mensagensDados.push({
            topic: nomeSerie,
            payload: dados.setpoint
        });

        configuracaoSeries.push({
            name: nomeSerie,
            type: "line",

            lineStyle: {
                color:
                    configuracao.corSetpoint,
                width: 2,
                type: "dashed"
            },

            itemStyle: {
                color:
                    configuracao.corSetpoint
            }
        });
    }
}

// ============================================================
// VERIFICAÇÃO DOS RESULTADOS
// ============================================================

if (mensagensDados.length === 0) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: "nenhum ponto válido"
    });

    return [[{
        payload: [],
        action: "replace"
    }]];
}

// ============================================================
// AÇÃO DE ATUALIZAÇÃO DO GRÁFICO
// ============================================================

mensagensDados.forEach(
    (mensagem, indice) => {
        /*
         * A primeira série limpa o gráfico.
         * As demais são adicionadas posteriormente.
         */
        mensagem.action =
            indice === 0
                ? "replace"
                : "append";
    }
);

// ============================================================
// CONFIGURAÇÃO VISUAL DAS SÉRIES
// ============================================================

const mensagemConfiguracao = {
    ui_update: {
        chartOptions: {
            series: configuracaoSeries
        }
    }
};

// ============================================================
// STATUS DO NÓ
// ============================================================

const totalPontos =
    mensagensDados.reduce(
        (soma, mensagem) =>
            soma + mensagem.payload.length,
        0
    );

node.status({
    fill: "green",
    shape: "dot",
    text:
        `${mensagensDados.length} séries | ` +
        `${totalPontos} pontos`
});

// Uma saída, com várias mensagens sequenciais
return [[
    mensagemConfiguracao,
    ...mensagensDados
]];

// ============================================================
// FORMATAR INDICADORES
// ============================================================

const linha =
    Array.isArray(msg.payload) &&
        msg.payload.length > 0
        ? msg.payload[0]
        : null;

if (!linha) {
    return [
        { payload: "--" },
        { payload: "--" },
        { payload: "--" },
        { payload: "--" }
    ];
}

function temperatura(valor) {
    const numero = Number(valor);

    return Number.isFinite(numero)
        ? `${numero.toFixed(1)} °C`
        : "--";
}

function percentual(valor) {
    const numero = Number(valor);

    return Number.isFinite(numero)
        ? `${numero.toFixed(1)} %`
        : "--";
}

return [
    {
        payload:
            temperatura(
                linha.temperatura_minima
            )
    },
    {
        payload:
            temperatura(
                linha.temperatura_media
            )
    },
    {
        payload:
            temperatura(
                linha.temperatura_maxima
            )
    },
    {
        payload:
            percentual(
                linha.percentual_alerta
            )
    }
];

// ============================================================
// SEPARA AS MENSAGENS DOS TRÊS ESP32
// ============================================================

const dados = msg.payload;

if (
    dados === null ||
    typeof dados !== "object" ||
    Array.isArray(dados)
) {
    node.warn("Payload recebido não é um objeto JSON.");
    return [null, null, null];
}

// Obtém o identificador pelo JSON
let deviceId = String(
    dados.device_id || ""
).trim();

// Caso não exista no JSON, tenta obter pelo tópico MQTT
if (deviceId === "") {
    const resultado = /^ESP32\/([^/]+)\/status$/.exec(
        String(msg.topic || "")
    );

    if (resultado) {
        deviceId = resultado[1];
    }
}

if (deviceId === "") {
    node.warn("Não foi possível identificar o ESP32.");
    return [null, null, null];
}

// Normalização dos dados
msg.device_id = deviceId;

msg.payload = {
    device_id: deviceId,

    temperature: Number(dados.temperature),

    setpoint: Number(
        dados.setpoint ??
        dados.threshold ??
        60
    ),

    alarm:
        Number(dados.alarm) === 1
            ? 1
            : 0,

    sprinkler:
        Number(dados.sprinkler) === 1
            ? 1
            : 0,

    state:
        String(
            dados.state || "desconhecido"
        ),

    wifi_rssi:
        Number(dados.wifi_rssi),

    received_at:
        Date.now()
};

// Distribuição pelas três saídas
switch (deviceId) {
    case "esp32-01":
        return [msg, null, null];

    case "esp32-02":
        return [null, msg, null];

    case "esp32-03":
        return [null, null, msg];

    default:
        node.warn(
            `Dispositivo não cadastrado: ${deviceId}`
        );

        return [null, null, null];
}

// ============================================================
// PREPARA OS WIDGETS DO ESP32
//
// Saída 1: Gauge de temperatura
// Saída 2: Estado geral
// Saída 3: Setpoint atual
// Saída 4: Estado do sprinkler
// Saída 5: Entrada numérica do setpoint
// ============================================================

const dados = msg.payload;

const temperatura =
    Number(dados.temperature);

const setpoint =
    Number(dados.setpoint);

if (
    !Number.isFinite(temperatura) ||
    !Number.isFinite(setpoint)
) {
    node.warn(
        "Temperatura ou setpoint inválido."
    );

    return [
        null,
        null,
        null,
        null,
        null
    ];
}

// A faixa de atenção começa 10 °C antes do setpoint
const inicioAtencao =
    Math.max(0, setpoint - 10);

// Gauge
const gauge = {
    payload: temperatura,

    ui_update: {
        min: 0,
        max: 100,

        segments: [
            {
                from: 0,
                color: "#2E7D32"
            },
            {
                from: inicioAtencao,
                color: "#F9A825"
            },
            {
                from: setpoint,
                color: "#C62828"
            }
        ]
    }
};

// Estado geral
const estado = {
    payload:
        dados.alarm === 1
            ? "ALERTA"
            : "NORMAL"
};

// Setpoint exibido
const setpointTexto = {
    payload:
        `${setpoint.toFixed(1)} °C`
};

// Estado do sprinkler
const sprinkler = {
    payload:
        dados.sprinkler === 1
            ? "ATIVO"
            : "INATIVO"
};

// Atualiza o campo de entrada com o setpoint atual
const setpointEntrada = {
    payload: setpoint
};

return [
    gauge,
    estado,
    setpointTexto,
    sprinkler,
    setpointEntrada
];

