);

const resultado =
    /^ESP32\/([^/]+)\/availability$/.exec(
        topico
    );

if (!resultado) {
    return [null, null, null];
}

const deviceId = resultado[1];

const valor = String(
    msg.payload || ""
)
    .trim()
    .toLowerCase();

msg.payload =
    valor === "online"
        ? "ONLINE"
        : "OFFLINE";

switch (deviceId) {
    case "esp32-01":
        return [msg, null, null];

    case "esp32-02":
        return [null, msg, null];

    case "esp32-03":
        return [null, null, msg];

    default:
        return [null, null, null];
}

let comando = msg.payload;

// Permite receber JSON em formato de texto
if (typeof comando === "string") {
    try {
        comando = JSON.parse(comando);
    } catch (erro) {
        node.warn(
            "Payload do comando não é um JSON válido."
        );

        return null;
    }
}

if (
    comando === null ||
    typeof comando !== "object"
) {
    node.warn(
        "Estrutura do comando inválida."
    );

    return null;
}

const alvo = String(
    comando.target || ""
);

const tipoComando = String(
    comando.command || ""
);

const valor = Number(
    comando.value
);

const alvosPermitidos = [
    "esp32-01",
    "esp32-02",
    "esp32-03",
    "all"
];

const comandosPermitidos = [
    "alarm",
    "reset",
    "setpoint"
];

if (!alvosPermitidos.includes(alvo)) {
    node.warn(
        `Destino inválido: ${alvo}`
    );

    return null;
}

if (
    !comandosPermitidos.includes(
        tipoComando
    )
) {
    node.warn(
        `Comando inválido: ${tipoComando}`
    );

    return null;
}

// Define o tópico individual ou geral
msg.topic =
    `ESP32/${alvo}/command`;

// O ESP32 espera uma string JSON
msg.payload = JSON.stringify({
    command: tipoComando,
    value: valor
});

// Comandos não devem ser retidos
msg.retain = false;

return msg;

const valor = Number(msg.payload);

if (!Number.isFinite(valor)) {
    node.status({
        fill: "red",
        shape: "ring",
        text: "valor inválido"
    });

    node.warn("Setpoint inválido.");
    return null;
}

if (valor < 0 || valor > 100) {
    node.status({
